@RestController
public class WebhookHandler {

    @Autowired
    private RestTemplate restTemplate;

    @PostMapping("/webhooks")
    public ResponseEntity<String> handleWebhook(@RequestBody String payload) throws Exception {
        // Fetch the content from the URL provided in the payload
        String url = getUrlFromPayload(payload);
        HttpHeaders headers = new HttpHeaders();
        headers.setAccept(Arrays.asList(MediaType.APPLICATION_JSON));
        ResponseEntity<String> response = restTemplate.exchange(url, HttpMethod.GET, new HttpEntity<>(headers), String.class);

        // Process the content and return the response
        String processedContent = processContent(response.getBody());
        return new ResponseEntity<>(processedContent, HttpStatus.OK);
    }

    private String getUrlFromPayload(String payload) {
        // Extract the URL from the payload
        JSONObject jsonObject = new JSONObject(payload);
        return jsonObject.getString("url");
    }

    private String processContent(String content) {
        // Process the content and return the processed content
        // This method can be customized based on the requirements of your service
        return content;
    }
}